  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ user, setRole, onLogout }) => {
  // Définition des accès par rôle (RBAC)
  const menuConfig = [
    { role: Role.ADMIN, icon: LayoutDashboard, label: 'Tableau de Bord', access: [Role.ADMIN, Role.ACCOUNTANT] },
    { role: Role.RECEPTION, icon: Users, label: 'Accueil', access: [Role.ADMIN, Role.RECEPTION] },
    { role: Role.DOCTOR, icon: Stethoscope, label: 'Consultations', access: [Role.ADMIN, Role.DOCTOR] },
