    { role: Role.MATERNITY, icon: Baby, label: 'Maternité', access: [Role.ADMIN, Role.MATERNITY, Role.DOCTOR] },
    { role: Role.PHARMACY, icon: Pill, label: 'Pharmacie', access: [Role.ADMIN, Role.PHARMACY] },
    { role: Role.CASHIER, icon: CreditCard, label: 'Caisse & Facturation', access: [Role.ADMIN, Role.CASHIER, Role.ACCOUNTANT] },
    { role: Role.ACCOUNTANT, icon: TrendingUp, label: 'Gestion & Compta', access: [Role.ADMIN, Role.ACCOUNTANT] },
