export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Role, User } from './types';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import Reception from './pages/Reception';
import Consultation from './pages/Consultation';
import Inpatient from './pages/Inpatient';
import Lab from './pages/Lab';
import Maternity from './pages/Maternity';
import Pharmacy from './pages/Pharmacy';
import Accounting from './pages/Accounting';
import Personnel from './pages/Personnel';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentModule, setCurrentModule] = useState<Role | null>(null);

  // Redirection automatique selon le rôle lors de la connexion
  useEffect(() => {
    if (user) {
      setCurrentModule(user.role);
    }
  }, [user]);

  const handleLogin = (userData: User) => {
    setUser(userData);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentModule(null);
  };

  const renderModule = () => {
    if (!user || !currentModule) return null;

    switch(currentModule) {
      case Role.ADMIN: return <Dashboard />;
      case Role.RECEPTION: return <Reception />;
      case Role.DOCTOR: return <Consultation />;
      case Role.NURSE: return <Inpatient />;
      case Role.LAB: return <Lab />;
      case Role.PHARMACY: return <Pharmacy />;
      case Role.CASHIER: return <Accounting />;
      case Role.MATERNITY: return <Maternity />;
      case Role.ACCOUNTANT: return <Accounting />; // Or a specific management module
      default: return <Dashboard />;
    }
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <Sidebar 
        user={user} 
        currentRole={currentModule || user.role} 
        setRole={setCurrentModule} 
        onLogout={handleLogout} 
      />

      <main className="flex-1 ml-64 min-h-screen relative">
        <div className="max-w-[1600px] mx-auto">
          {renderModule()}
        </div>

        {/* Notifications persistantes contextuelles */}
        <div className="fixed bottom-8 right-8 z-50 pointer-events-none">
          <div className="space-y-3 flex flex-col items-end">
            <div className="bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4 pointer-events-auto border border-slate-800 transform hover:scale-105 transition-transform cursor-pointer group">
              <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse group-hover:bg-blue-400"></div>
              <div>
                <p className="text-[10px] font-black uppercase text-slate-500">Session Active</p>
                <p className="text-xs font-bold">{user.name} • {user.role}</p>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

