    { id: 'DME-4452', firstName: 'Amadou', lastName: 'DIOP', birthDate: '1985-05-12', gender: 'M', phone: '771234567', residence: 'Dakar Plateau', emergencyContact: 'Mariam Diop', emergencyPhone: '778889900', maritalStatus: 'MARIE', status: PatientStatus.DISCHARGED },
    { id: 'DME-9012', firstName: 'Mariam', lastName: 'SYLLA', birthDate: '1992-10-20', gender: 'F', phone: '765554433', residence: 'Medina', emergencyContact: 'Ibrahim Sylla', emergencyPhone: '761112233', maritalStatus: 'MARIE', status: PatientStatus.IN_MATERNITY },
  ]);

  const [dailyTransactions, setDailyTransactions] = useState<any[]>([
    { id: 'T-992', time: '08:45', patient: 'DIOP Amadou', dme: 'DME-4452', motif: 'CONSULTATION', total: 10000, paid: 10000, remaining: 0, status: 'SOLDE', type: 'MEDICAL' },
    { id: 'T-994', time: '10:05', patient: 'KEITA Ibrahim', dme: 'DME-1102', motif: 'LABORATOIRE', total: 12500, paid: 5000, remaining: 7500, status: 'PARTIEL', type: 'MEDICAL' },
  ]);

  const [currentPatient, setCurrentPatient] = useState<Partial<Patient>>({});
  const [visitMotif, setVisitMotif] = useState<VisitMotif | null>(null);
  const [notebookAdded, setNotebookAdded] = useState(false);
  const [showUpsell, setShowUpsell] = useState(false);

  // États de paiement
  const [amountReceived, setAmountReceived] = useState<string>('');
  const [showProforma, setShowProforma] = useState(false);
  const [selectedTxForProforma, setSelectedTxForProforma] = useState<any>(null);

  const totalToPay = useMemo(() => {
    if (!visitMotif) return 0;
    return getOrientationData(visitMotif).fee + (notebookAdded ? 1000 : 0);
  }, [visitMotif, notebookAdded]);

  const remainingToPay = useMemo(() => {
    const received = parseFloat(amountReceived) || 0;
    return Math.max(0, totalToPay - received);
  }, [totalToPay, amountReceived]);

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

