import React, { useState, useMemo } from 'react';
import { CreditCard, DollarSign, ArrowUpRight, Printer, Search, Calendar, Landmark, CheckCircle2, Edit3, X, Calculator, Wallet } from 'lucide-react';

const Accounting = () => {
  const [activeTab, setActiveTab] = useState<'daily' | 'invoices' | 'reports'>('daily');
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<any>(null);
  const [additionalPayment, setAdditionalPayment] = useState<string>('');

  const [transactions, setTransactions] = useState([
    { id: 'T-4452', time: '12:45', patient: 'DIOP Amadou', dme: 'DME-4452', desc: 'Consultation Générale', total: 10000, paid: 10000, remaining: 0, status: 'SOLDE' },
    { id: 'T-9012', time: '12:30', patient: 'SYLLA Mariam', dme: 'DME-9012', desc: 'Kit Accouchement', total: 85000, paid: 40000, remaining: 45000, status: 'PARTIEL' },
    { id: 'T-1102', time: '12:15', patient: 'KEITA Ibrahim', dme: 'DME-1102', desc: 'Examens Labo (NFS)', total: 12500, paid: 12500, remaining: 0, status: 'SOLDE' },
  ]);

  const unpaidInvoices = useMemo(() => transactions.filter(t => t.remaining > 0), [transactions]);

  const handleOpenPayment = (invoice: any) => {
    setSelectedInvoice(invoice);
    setShowPaymentModal(true);
    setAdditionalPayment('');
  };

  const processReliquat = () => {
    const amount = parseFloat(additionalPayment) || 0;
    if (amount <= 0) return;

    setTransactions(prev => prev.map(t => {
      if (t.id === selectedInvoice.id) {
        const newPaid = t.paid + amount;
        const newRemaining = Math.max(0, t.total - newPaid);
        return {
          ...t,
          paid: newPaid,
          remaining: newRemaining,
          status: newRemaining === 0 ? 'SOLDE' : 'PARTIEL'
        };
      }
      return t;
    }));

    setShowPaymentModal(false);
    alert("Reliquat encaissé avec succès.");
  };

  return (
    <div className="p-8 text-slate-900">
      {/* Modal Règlement Reliquat */}
