import React, { useState, useEffect, useMemo } from 'react';
import { 
  Search, UserPlus, Phone, MapPin, Heart, 
  Users, Stethoscope, Beaker, Baby, Pill, 
  Activity, AlertCircle, ChevronRight, Save,
  CheckCircle2, CreditCard, ShieldAlert, Calendar,
  Briefcase, DollarSign, Clock, UserCheck, Printer,
  LogOut, ShoppingBag, FileText, CheckCircle, X,
  User as UserIcon, Wallet, Calculator, ArrowRightLeft
} from 'lucide-react';
import { Patient, VisitMotif, Role, User as UserType, PatientStatus, Consumable } from '../types';

interface ReceptionProps {
  user?: UserType;
}

const getOrientationData = (motif: VisitMotif) => {
  switch(motif) {
    case 'CONSULTATION': return { dest: Role.DOCTOR, fee: 10000, label: 'Consultation Générale' };
    case 'URGENCE': return { dest: Role.DOCTOR, fee: 15000, label: 'Urgences Vitales' };
    case 'LABORATOIRE': return { dest: Role.LAB, fee: 0, label: 'Prélèvements' };
    case 'MATERNITE': return { dest: Role.MATERNITY, fee: 5000, label: 'Suivi de Grossesse' };
    case 'SOIN_INFIRMIER': return { dest: Role.NURSE, fee: 2500, label: 'Soins / Pansements' };
    default: return { dest: Role.DOCTOR, fee: 10000, label: 'Général' };
  }
};

const Reception: React.FC<ReceptionProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'triage' | 'sorties' | 'caisse' | 'profil'>('triage');
  const [step, setStep] = useState<'search' | 'register' | 'triage' | 'payment' | 'summary'>('search');
  const [searchQuery, setSearchQuery] = useState('');

  const [patients, setPatients] = useState<Patient[]>([
    { id: 'DME-4452', firstName: 'Amadou', lastName: 'DIOP', birthDate: '1985-05-12', gender: 'M', phone: '771234567', residence: 'Dakar Plateau', emergencyContact: 'Mariam Diop', emergencyPhone: '778889900', maritalStatus: 'MARIE', status: PatientStatus.DISCHARGED },
    { id: 'DME-9012', firstName: 'Mariam', lastName: 'SYLLA', birthDate: '1992-10-20', gender: 'F', phone: '765554433', residence: 'Medina', emergencyContact: 'Ibrahim Sylla', emergencyPhone: '761112233', maritalStatus: 'MARIE', status: PatientStatus.IN_MATERNITY },
  ]);

  const [dailyTransactions, setDailyTransactions] = useState<any[]>([
    { id: 'T-992', time: '08:45', patient: 'DIOP Amadou', dme: 'DME-4452', motif: 'CONSULTATION', total: 10000, paid: 10000, remaining: 0, change: 0, status: 'SOLDE', type: 'MEDICAL' },
    { id: 'T-994', time: '10:05', patient: 'KEITA Ibrahim', dme: 'DME-1102', motif: 'LABORATOIRE', total: 12500, paid: 5000, remaining: 7500, change: 0, status: 'PARTIEL', type: 'MEDICAL' },
  ]);

  const [currentPatient, setCurrentPatient] = useState<Partial<Patient>>({});
  const [visitMotif, setVisitMotif] = useState<VisitMotif | null>(null);
  const [notebookAdded, setNotebookAdded] = useState(false);
  const [showUpsell, setShowUpsell] = useState(false);

  const [amountReceived, setAmountReceived] = useState<string>('');
  const [showProforma, setShowProforma] = useState(false);
  const [selectedTxForProforma, setSelectedTxForProforma] = useState<any>(null);

  const totalToPay = useMemo(() => {
    if (!visitMotif) return 0;
    return getOrientationData(visitMotif).fee + (notebookAdded ? 1000 : 0);
  }, [visitMotif, notebookAdded]);

  // Algorithme de calcul du reliquat et du rendu
  const paymentStats = useMemo(() => {
    const received = parseFloat(amountReceived) || 0;
    const diff = received - totalToPay;
    return {
      received,
      remaining: diff < 0 ? Math.abs(diff) : 0,
      change: diff > 0 ? diff : 0
    };
  }, [totalToPay, amountReceived]);

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);

  const [consumables, setConsumables] = useState<Consumable[]>([
    { id: 'C-01', name: 'Carnet Médical', price: 1000, stock: 150 },
    { id: 'C-02', name: 'Dossier Hospitalisation', price: 2500, stock: 45 },
    { id: 'C-03', name: 'Fiche Administrative', price: 200, stock: 500 },
  ]);

  const [patientsToDischarge, setPatientsToDischarge] = useState([
    { id: 'P-101', name: 'DIALLO Mamadou', admissionDate: '12/05/2024', department: 'Médecine Interne', status: PatientStatus.READY_TO_DISCHARGE },
    { id: 'P-102', name: 'SOW Aminata', admissionDate: '10/05/2024', department: 'Maternité', status: PatientStatus.READY_TO_DISCHARGE },
  ]);

  const agentProfile = user || {
    name: "Moussa Diop",
    profession: "Agent d'accueil Principal",
    role: Role.RECEPTION,
    schedule: "Lun-Ven (08h00 - 17h00)",
    salary: "250,000 CFA",
    quotePartRate: "1%"
  };

  const totalDaily = dailyTransactions.reduce((acc, curr) => acc + curr.paid, 0);

  const filteredPatients = useMemo(() => {
    if (!searchQuery.trim()) return [];
    return patients.filter(p => 
      p.lastName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.firstName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.id.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery, patients]);

  useEffect(() => {
    if (visitMotif === 'CONSULTATION' || visitMotif === 'SOIN_INFIRMIER') {
      setShowUpsell(true);
    } else {
      setShowUpsell(false);
    }
  }, [visitMotif]);

  const handleSelectPatient = (p: Patient) => {
    setCurrentPatient(p);
    setStep('triage');
    setSearchQuery('');
  };

  const finalizeAdmission = () => {
    const newTx = {
      id: `T-${Math.floor(Math.random() * 900) + 100}`,
      time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
      patient: `${currentPatient.lastName} ${currentPatient.firstName}`,
      dme: currentPatient.id,
      motif: visitMotif,
      total: totalToPay,
      paid: paymentStats.received,
      remaining: paymentStats.remaining,
      change: paymentStats.change,
      status: paymentStats.remaining === 0 ? 'SOLDE' : (paymentStats.received > 0 ? 'PARTIEL' : 'IMPAYE'),
      type: 'MEDICAL'
    };

    if (!patients.find(p => p.id === currentPatient.id)) {
      setPatients([...patients, currentPatient as Patient]);
    }

    setDailyTransactions([newTx, ...dailyTransactions]);
    setSelectedTxForProforma(newTx);
    setStep('summary');
  };

  const handleAddConsumable = (item: Consumable) => {
    if (item.stock <= 0) return;
    setConsumables(prev => prev.map(c => c.id === item.id ? { ...c, stock: c.stock - 1 } : c));
    const newTx = {
      id: `V-${Math.floor(Math.random() * 900) + 100}`,
      time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
      patient: 'Vente Boutique',
      motif: item.name as any,
      total: item.price,
      paid: item.price,
      remaining: 0,
      change: 0,
      status: 'SOLDE',
      type: 'BOUTIQUE'
    };
    setDailyTransactions([newTx, ...dailyTransactions]);
  };

  const handleDischarge = (patientId: string) => {
    setPatientsToDischarge(prev => prev.filter(p => p.id !== patientId));
    alert("Hospitalisation clôturée administrativement. Autorisation de sortie générée.");
  };

  return (
    <div className="p-8 max-w-7xl mx-auto text-slate-900">
      {/* Modal Pro-forma avec Détail Paiement */}
      {showProforma && selectedTxForProforma && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10">
               <div className="flex justify-between items-start mb-10">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-bold text-white italic">SH</div>
                    <div>
                      <h2 className="text-xl font-black uppercase tracking-tighter">SmartHosto SIH</h2>
                      <p className="text-[10px] font-bold text-slate-400">Ticket de Caisse • {selectedTxForProforma.id}</p>
                    </div>
                  </div>
                  <button onClick={() => setShowProforma(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24} className="text-slate-400" /></button>
               </div>

               <div className="grid grid-cols-2 gap-10 mb-8 border-b border-dashed border-slate-200 pb-8">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Dossier Patient</p>
                    <p className="font-bold text-lg">{selectedTxForProforma.patient}</p>
                    <p className="text-xs text-blue-600 font-mono font-bold">{selectedTxForProforma.dme}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Régulation</p>
                    <p className="font-bold text-sm">{new Date().toLocaleDateString('fr-FR')} • {selectedTxForProforma.time}</p>
                    <p className="text-xs text-slate-500 font-bold">Guichet: {agentProfile.name}</p>
                  </div>
               </div>

               <div className="space-y-4 mb-8">
                  <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl">
                     <span className="text-sm font-bold text-slate-600 italic">{selectedTxForProforma.motif}</span>
                     <span className="font-black text-slate-900">{selectedTxForProforma.total.toLocaleString()} CFA</span>
                  </div>
               </div>

               <div className="bg-slate-900 text-white p-8 rounded-[32px] mb-8 space-y-4">
                  <div className="flex justify-between text-slate-400 text-xs font-bold uppercase tracking-widest">
                    <span>Net à Payer</span>
                    <span className="text-white">{selectedTxForProforma.total.toLocaleString()} CFA</span>
                  </div>
                  <div className="flex justify-between text-blue-400 text-xs font-bold uppercase tracking-widest">
                    <span>Espèces Reçues</span>
                    <span className="text-white">{selectedTxForProforma.paid.toLocaleString()} CFA</span>
                  </div>
                  <div className="pt-4 border-t border-white/10 flex justify-between items-center">
                    {selectedTxForProforma.change > 0 ? (
                       <>
                         <span className="text-xs font-black uppercase text-emerald-400">Monnaie Rendue</span>
                         <span className="text-3xl font-black text-emerald-400">{selectedTxForProforma.change.toLocaleString()} <span className="text-xs">CFA</span></span>
                       </>
                    ) : (
                       <>
                         <span className="text-xs font-black uppercase text-rose-400">Reste à Payer</span>
                         <span className="text-3xl font-black text-rose-400">{selectedTxForProforma.remaining.toLocaleString()} <span className="text-xs">CFA</span></span>
                       </>
                    )}
                  </div>
               </div>

               <button onClick={() => window.print()} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black shadow-xl hover:bg-blue-600 transition-all flex items-center justify-center gap-3">
                 <Printer size={20} /> Imprimer Ticket
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Header Principal */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
        <div>
          <h1 className="text-4xl font-black tracking-tight">Espace Accueil SIH</h1>
          <p className="text-slate-500 font-medium">Gestion temps-réel des admissions et transactions de caisse.</p>
        </div>

        <div className="bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-1 overflow-x-auto">
          {[
            { id: 'triage', label: 'Admissions', icon: Users },
            { id: 'sorties', label: 'Sorties', icon: LogOut },
            { id: 'caisse', label: 'Caisse', icon: CreditCard },
            { id: 'profil', label: 'Profil', icon: UserCheck },
          ].map((tab) => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon size={14} /> {tab.label}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'triage' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            {step === 'search' && (
              <div className="bg-white p-10 rounded-[40px] shadow-sm border border-slate-200">
                <h2 className="text-xl font-bold mb-6 flex items-center gap-2"><Search size={24} className="text-blue-600" /> Identifier Patient</h2>
                <div className="relative mb-4">
                  <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
                  <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Nom ou N° DME..." className="w-full pl-16 pr-6 py-6 bg-slate-50 border-2 border-slate-100 rounded-3xl focus:outline-none focus:border-blue-500 focus:bg-white transition-all text-xl font-medium" />
                </div>
                {searchQuery.length > 0 && (
                  <div className="mb-8 overflow-hidden rounded-3xl border border-slate-100 bg-slate-50 animate-in fade-in duration-300">
                    {filteredPatients.length > 0 ? filteredPatients.map(p => (
                      <button key={p.id} onClick={() => handleSelectPatient(p)} className="w-full p-6 flex items-center justify-between hover:bg-blue-50 transition-colors border-b last:border-0 border-slate-100 group">
                        <div className="flex items-center gap-4 text-left">
                          <div className="w-12 h-12 rounded-2xl bg-white flex items-center justify-center text-slate-400 group-hover:text-blue-600 shadow-sm"><UserIcon size={24} /></div>
                          <div><p className="font-black text-slate-900">{p.lastName} {p.firstName}</p><p className="text-xs text-slate-500 font-bold font-mono">{p.id} • {p.residence}</p></div>
                        </div>
                        <ChevronRight size={20} className="text-slate-300 group-hover:text-blue-600" />
                      </button>
                    )) : <div className="p-10 text-center"><p className="text-slate-400 font-bold text-sm">Aucun dossier trouvé pour "{searchQuery}"</p></div>}
                  </div>
                )}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button onClick={() => { setCurrentPatient({ id: `DME-${Math.floor(Math.random()*9000)+1000}` }); setStep('register'); }} className="p-8 border-2 border-dashed border-slate-200 rounded-3xl hover:border-blue-500 hover:bg-blue-50/50 transition-all group flex flex-col items-center text-center">
                    <UserPlus size={40} className="text-slate-300 group-hover:text-blue-500 mb-4 transition-colors" /><h3 className="font-bold">Nouveau Patient</h3><p className="text-xs text-slate-500 font-medium">Création de dossier DME</p>
                  </button>
                  <div className="p-8 bg-slate-50 rounded-3xl border-2 border-slate-100 opacity-50 flex flex-col items-center text-center">
                    <ShieldAlert size={40} className="text-slate-300 mb-4" /><h3 className="font-bold">Urgence Inconnue</h3>
                  </div>
                </div>
              </div>
            )}

            {step === 'register' && (
              <div className="bg-white p-10 rounded-[40px] shadow-sm border border-slate-200">
                <div className="flex justify-between items-center mb-8">
                  <h2 className="text-2xl font-black italic">Admission DME <span className="text-blue-600 font-mono text-lg ml-4">{currentPatient?.id}</span></h2>
                  <button onClick={() => setStep('search')} className="text-slate-400 hover:text-slate-900 font-bold text-xs uppercase">Annuler</button>
                </div>
                <div className="grid grid-cols-2 gap-6 mb-8 text-slate-900">
                  <div className="space-y-4">
                    <input type="text" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 outline-none focus:border-blue-500" placeholder="Nom" value={currentPatient.lastName || ''} onChange={e => setCurrentPatient({...currentPatient, lastName: e.target.value})} />
                    <input type="text" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 outline-none focus:border-blue-500" placeholder="Prénom" value={currentPatient.firstName || ''} onChange={e => setCurrentPatient({...currentPatient, firstName: e.target.value})} />
                  </div>
                  <div className="space-y-4">
                    <input type="text" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 outline-none focus:border-blue-500" placeholder="Résidence" value={currentPatient.residence || ''} onChange={e => setCurrentPatient({...currentPatient, residence: e.target.value})} />
                    <input type="tel" className="w-full p-4 bg-slate-50 rounded-2xl border border-slate-100 outline-none focus:border-blue-500" placeholder="Téléphone" value={currentPatient.phone || ''} onChange={e => setCurrentPatient({...currentPatient, phone: e.target.value})} />
                  </div>
                </div>
                <button onClick={() => setStep('triage')} disabled={!currentPatient.lastName || !currentPatient.firstName} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black shadow-xl hover:bg-blue-600 transition-all disabled:opacity-50 flex items-center justify-center gap-2">Suivant: Motif & Triage <ChevronRight size={18} /></button>
              </div>
            )}

            {step === 'triage' && (
              <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
                <div className="bg-white p-10 rounded-[40px] shadow-sm border border-slate-200 text-slate-900">
                  <div className="flex justify-between items-center mb-10">
                    <h2 className="text-2xl font-black">Motif de Venue</h2>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Patient Sélectionné</p>
                       <p className="font-bold text-slate-900">{currentPatient.lastName} {currentPatient.firstName}</p>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    {[
                      { id: 'CONSULTATION', icon: Stethoscope, label: 'Consultation', color: 'blue' },
                      { id: 'URGENCE', icon: ShieldAlert, label: 'Urgence', color: 'red' },
                      { id: 'LABORATOIRE', icon: Beaker, label: 'Labo / Examens', color: 'purple' },
                      { id: 'SOIN_INFIRMIER', icon: Activity, label: 'Soins / Pansements', color: 'emerald' },
                    ].map((m) => (
                      <button key={m.id} onClick={() => setVisitMotif(m.id as VisitMotif)} className={`p-8 rounded-[32px] border-2 transition-all flex flex-col items-center gap-4 text-center ${visitMotif === m.id ? `border-${m.color}-500 bg-${m.color}-50 shadow-lg scale-105` : 'border-slate-100 bg-slate-50 hover:border-slate-300'}`}>
                        <m.icon size={28} className={visitMotif === m.id ? `text-${m.color}-600` : 'text-slate-400'} />
                        <span className="font-black text-xs uppercase tracking-widest">{m.label}</span>
                      </button>
                    ))}
                  </div>
                </div>

                {showUpsell && (
                  <div className="bg-amber-50 border-2 border-amber-200 p-8 rounded-[40px] flex items-center justify-between animate-in bounce-in">
                    <div className="flex items-center gap-6 text-slate-900">
                      <div className="w-16 h-16 bg-amber-200 text-amber-700 rounded-3xl flex items-center justify-center animate-pulse"><ShoppingBag size={32} /></div>
                      <div><h4 className="font-black">Carnet Médical SmartHosto</h4><p className="text-xs text-amber-700">Recommandé pour tout nouveau patient ou suivi annuel.</p></div>
                    </div>
                    <button onClick={() => setNotebookAdded(!notebookAdded)} className={`px-8 py-4 rounded-2xl font-black text-sm transition-all ${notebookAdded ? 'bg-emerald-600 text-white' : 'bg-amber-600 text-white shadow-lg'}`}>
                      {notebookAdded ? 'Carnet Inclus (+1000)' : 'Ajouter Carnet'}
                    </button>
                  </div>
                )}

                {visitMotif && (
                  <button onClick={() => setStep('payment')} className="w-full bg-slate-900 text-white py-6 rounded-[40px] font-black shadow-2xl hover:bg-blue-600 transition-all flex items-center justify-center gap-4">
                    <CreditCard size={24} /> Passer à l'Encaissement ({totalToPay.toLocaleString()} CFA)
                  </button>
                )}
              </div>
            )}

            {/* INTERFACE DE CALCUL DE CAISSE INTELLIGENTE */}
            {step === 'payment' && (
              <div className="bg-white p-10 rounded-[40px] shadow-sm border border-slate-200 animate-in zoom-in-95 duration-300 text-slate-900">
                <div className="flex items-center gap-4 mb-10">
                   <div className="p-4 bg-emerald-100 text-emerald-700 rounded-3xl"><Calculator size={24} /></div>
                   <div>
                     <h2 className="text-2xl font-black">Calculateur d'Encaissement</h2>
                     <p className="text-sm text-slate-500 font-medium">Saisissez le montant donné par le patient pour calculer le reliquat ou le rendu.</p>
                   </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 mb-10">
                   <div className="space-y-6">
                      <div className="p-8 bg-slate-50 rounded-[32px] border border-slate-100">
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Total à Encaisser</p>
                         <p className="text-4xl font-black text-slate-900">{totalToPay.toLocaleString()} <span className="text-sm font-normal opacity-50 italic">CFA</span></p>
                      </div>

                      <div className="relative">
                         <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-3 ml-4">Montant Donné (Espèces)</label>
                         <div className="relative group">
                            <Wallet className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-emerald-500 transition-colors" size={24} />
                            <input 
                              type="number" 
                              value={amountReceived}
                              onChange={(e) => setAmountReceived(e.target.value)}
                              placeholder="0"
                              className="w-full pl-16 pr-8 py-8 bg-slate-50 border-2 border-slate-100 rounded-[32px] focus:outline-none focus:border-emerald-500 focus:bg-white transition-all text-2xl font-black text-slate-900"
                              autoFocus
                            />
                         </div>
                      </div>
                   </div>

                   <div className="bg-slate-900 p-10 rounded-[40px] text-white flex flex-col justify-center items-center text-center relative overflow-hidden group">
                      <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform"><ArrowRightLeft size={100} /></div>

                      {/* Affichage intelligent basé sur le calcul */}
                      {paymentStats.received === 0 ? (
                         <>
                           <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2 italic">En attente de saisie...</p>
                           <h4 className="text-5xl font-black text-slate-700 tracking-tighter">0 <span className="text-sm font-normal">CFA</span></h4>
                         </>
                      ) : paymentStats.change > 0 ? (
                         <>
                           <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest mb-2 animate-bounce">Monnaie à Rendre (Rendu)</p>
                           <h4 className="text-6xl font-black text-emerald-400 tracking-tighter">
                             {paymentStats.change.toLocaleString()} <span className="text-sm font-normal text-white italic">CFA</span>
                           </h4>
                         </>
                      ) : paymentStats.remaining > 0 ? (
                         <>
                           <p className="text-rose-400 text-[10px] font-black uppercase tracking-widest mb-2">Reliquat (Reste à payer)</p>
                           <h4 className="text-6xl font-black text-rose-400 tracking-tighter">
                             {paymentStats.remaining.toLocaleString()} <span className="text-sm font-normal text-white italic">CFA</span>
                           </h4>
                         </>
                      ) : (
                         <>
                           <CheckCircle size={48} className="text-emerald-500 mb-4" />
                           <h4 className="text-3xl font-black text-white">Compte Juste</h4>
                           <p className="text-xs text-slate-400 mt-2 font-bold italic">Transaction complète soldée.</p>
                         </>
                      )}
                   </div>
                </div>

                <div className="flex gap-4">
                  <button onClick={() => setStep('triage')} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-3xl font-black hover:bg-slate-200 transition-all flex items-center justify-center gap-2">Retour</button>
                  <button onClick={finalizeAdmission} className="flex-[2] bg-emerald-600 text-white py-5 rounded-3xl font-black shadow-xl shadow-emerald-600/20 hover:bg-emerald-700 transition-all flex items-center justify-center gap-3">
                    <CheckCircle2 size={24} /> Valider l'Admission & Ticket
                  </button>
                </div>
              </div>
            )}

            {step === 'summary' && (
              <div className="bg-white p-12 rounded-[40px] border border-slate-200 text-center animate-in zoom-in-95 text-slate-900">
                <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 border-4 border-white shadow-xl">
                  <CheckCircle2 size={48} className="text-emerald-500" />
                </div>
                <h2 className="text-3xl font-black mb-4">Paiement Enregistré</h2>
                <p className="text-slate-500 font-medium mb-10 max-w-sm mx-auto">Le ticket a été généré et le patient a été ajouté à la file d'attente médicale.</p>
                <div className="flex gap-4">
                   <button onClick={() => setShowProforma(true)} className="flex-1 bg-slate-100 py-5 rounded-3xl font-bold flex items-center justify-center gap-2 text-slate-600 hover:bg-slate-200 transition-colors"><Printer size={20} /> Reçu Pro-forma</button>
                   <button onClick={() => { setStep('search'); setAmountReceived(''); setNotebookAdded(false); setVisitMotif(null); }} className="flex-1 bg-blue-600 text-white py-5 rounded-3xl font-black hover:bg-blue-700 shadow-xl transition-all">Nouveau Patient</button>
                </div>
              </div>
            )}
          </div>

          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden text-slate-900">
              <div className="p-8 border-b bg-slate-50/50 flex justify-between items-center">
                <h3 className="font-black text-[10px] uppercase tracking-widest flex items-center gap-2 italic"><Activity size={16} /> File d'Attente</h3>
                <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-[10px] font-black tracking-tighter">
                  {dailyTransactions.filter(t => t.type === 'MEDICAL').length} PATIENTS
                </span>
              </div>
              <div className="divide-y divide-slate-100 max-h-[600px] overflow-y-auto">
                {dailyTransactions.filter(t => t.type === 'MEDICAL').map((p, i) => (
                  <div key={i} className="p-6 hover:bg-slate-50 group transition-colors relative overflow-hidden">
                    {p.remaining > 0 && <div className="absolute top-0 left-0 w-1 h-full bg-rose-500"></div>}
                    <div className="flex justify-between items-start mb-2">
                       <div>
                         <p className="font-bold text-sm text-slate-900">{p.patient}</p>
                         <p className="text-[10px] text-slate-400 font-black font-mono tracking-tight">{p.dme}</p>
                       </div>
                       <button onClick={() => { setSelectedTxForProforma(p); setShowProforma(true); }} className="p-2 text-slate-300 hover:text-blue-600 hover:bg-white rounded-xl transition-all"><Printer size={16} /></button>
                    </div>
                    <div className="flex justify-between items-center mt-3">
                       <span className={`text-[9px] font-black px-3 py-1 rounded-full border-2 ${p.remaining > 0 ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-emerald-50 text-emerald-600 border-emerald-100'}`}>
                         {p.remaining > 0 ? `RESTE: ${p.remaining.toLocaleString()} CFA` : 'SOLDÉ'}
                       </span>
                       <span className="text-[10px] text-slate-400 font-black italic">{p.time}</span>
                    </div>
                  </div>
                ))}
                {dailyTransactions.filter(t => t.type === 'MEDICAL').length === 0 && (
                  <div className="p-10 text-center italic text-slate-400 text-xs font-bold">Aucun patient enregistré aujourd'hui</div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Reste des onglets conservé... */}
    </div>
  );
};

export default Reception;

export enum PatientStatus {
  WAITING_ADMISSION = 'En attente accueil',
  WAITING_TRIAGE = 'En attente triage',
  IN_CONSULTATION = 'En consultation',
  WAITING_LAB = 'En attente Labo',
  INPATIENT = 'Hospitalisé',
  READY_TO_DISCHARGE = 'Prêt pour la sortie',
  IN_MATERNITY = 'En Maternité',
  DISCHARGED = 'Sorti'
}

export enum Role {
  ADMIN = 'ADMIN',
  RECEPTION = 'ACCUEIL',
  DOCTOR = 'MEDECIN',
  NURSE = 'INFIRMIER',
  LAB = 'LABO',
  MATERNITY = 'SAGE_FEMME',
  PHARMACY = 'PHARMACIEN',
  CASHIER = 'CAISSIER',
  ACCOUNTANT = 'GESTIONNAIRE'
}

export type VisitMotif = 
  | 'CONSULTATION' 
  | 'URGENCE' 
  | 'LABORATOIRE' 
  | 'MATERNITE' 
  | 'PHARMACIE' 
  | 'SOIN_INFIRMIER';

export interface Consumable {
  id: string;
  name: string;
  price: number;
  stock: number;
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: Role;
  token: string;
  profession?: string;
  salary?: string;
  schedule?: string;
  quotePartRate?: string;
}

export interface Patient {
  id: string;
  firstName: string;
  lastName: string;
  birthDate: string;
  gender: 'M' | 'F';
  phone: string;
  residence: string;
  emergencyContact: string;
  emergencyPhone: string;
  maritalStatus: 'CELIBATAIRE' | 'MARIE' | 'VEUF' | 'DIVORCE';
  ethnicity?: string;
  religion?: string;
  bloodGroup?: string;
  allergies?: string[];
  lastVisit?: string;
  status?: PatientStatus;
  // Paramètres cliniques de triage
  vitals?: {
    bpSys: number;
    bpDia: number;
    heartRate: number;
    respRate: number;
    pulse: number;
    spo2: number;
    temp: number;
    height: number;
    weight: number;
    bmi: number;
    waistCirc: number;
  };
}

export interface VisitRecord {
  id: string;
  patientId: string;
  motif: VisitMotif;
  priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'EMERGENCY';
