import React, { useState } from 'react';
import { 
  Stethoscope, 
  Activity, 
  Clock, 
  Brain, 
  FlaskConical, 
  Pill,
  Send,
  AlertTriangle,
  User as UserIcon,
  CheckCircle2
} from 'lucide-react';
import { getClinicalSupport } from '../services/geminiService';

interface ConsultationProps {
  waitingQueue: any[];
  setWaitingQueue: React.Dispatch<React.SetStateAction<any[]>>;
}

/**
 * Consultation component handles the medical examination of patients.
 * It integrates with Gemini AI to provide clinical decision support for doctors.
 */
const Consultation: React.FC<ConsultationProps> = ({ waitingQueue, setWaitingQueue }) => {
  const [selectedPatient, setSelectedPatient] = useState<any>(null);
  const [symptoms, setSymptoms] = useState('');
  const [geminiSupport, setGeminiSupport] = useState<any>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  const handleSelectPatient = (patient: any) => {
    setSelectedPatient(patient);
    setGeminiSupport(null);
    setSymptoms('');
  };

  /**
   * Triggers the AI analysis using symptoms and patient vitals.
   */
  const handleGeminiAnalysis = async () => {
    if (!selectedPatient || !symptoms) return;
    setLoadingAI(true);
    // Formatting patient vitals for the AI prompt to ensure high accuracy
    const vitalsStr = `Temp: ${selectedPatient.vitals.temp}°C, BP: ${selectedPatient.vitals.bp}, Pulse: ${selectedPatient.vitals.pulse}, SpO2: ${selectedPatient.vitals.spo2}%, BMI: ${selectedPatient.vitals.bmi}`;
    try {
      const result = await getClinicalSupport(symptoms, vitalsStr);
      setGeminiSupport(result);
    } catch (err) {
      console.error("AI Analysis failed:", err);
    } finally {
      setLoadingAI(false);
    }
  };

  /**
   * Finalizes the consultation and updates the global state.
   */
  const completeConsultation = () => {
    if (!selectedPatient) return;
    // Remove patient from waiting queue upon completion to move the flow forward
    setWaitingQueue(prev => prev.filter(p => p.id !== selectedPatient.id));
    setSelectedPatient(null);
    alert("Consultation terminée et enregistrée.");
  };

  return (
    <div className="p-8 max-w-7xl mx-auto text-slate-900">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="text-4xl font-black tracking-tight">Consultations</h1>
          <p className="text-slate-500 font-medium italic">Espace médecin • Aide au diagnostic assisté par IA.</p>
        </div>
        <div className="bg-blue-600 text-white px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20">
          {waitingQueue.length} PATIENTS EN ATTENTE
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Waiting Queue Section: List of patients from the triage/reception */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-8 border-b bg-slate-50/50 flex items-center justify-between">
              <h2 className="font-black text-[10px] uppercase tracking-widest italic flex items-center gap-2">
                <Clock size={16} /> File de Triage
              </h2>
            </div>
            <div className="divide-y divide-slate-100 max-h-[700px] overflow-y-auto">
              {waitingQueue.length > 0 ? waitingQueue.map((patient) => (
                <div 
                  key={patient.id} 
                  onClick={() => handleSelectPatient(patient)}
                  className={`p-8 cursor-pointer transition-all hover:bg-blue-50/50 group relative ${selectedPatient?.id === patient.id ? 'bg-blue-50' : ''}`}
                >
                  {selectedPatient?.id === patient.id && <div className="absolute left-0 top-0 w-1.5 h-full bg-blue-600"></div>}
                  <div className="flex justify-between items-start mb-3">
                    <span className="text-[10px] font-black text-slate-400 font-mono tracking-tighter uppercase">{patient.id}</span>
                    <span className={`px-3 py-1 rounded-xl text-[9px] font-black uppercase tracking-widest ${patient.motif === 'URGENCE' ? 'bg-rose-100 text-rose-600 border border-rose-200' : 'bg-blue-100 text-blue-600 border border-blue-200'}`}>
                      {patient.motif}
                    </span>
                  </div>
                  <h3 className="font-black text-slate-900 group-hover:text-blue-600 transition-colors">{patient.lastName} {patient.firstName}</h3>
                  <p className="text-xs text-slate-500 font-medium">{patient.age} ans • {patient.gender}</p>
                  <div className="mt-4 flex gap-2">
                    <span className="text-[10px] bg-white border border-slate-100 px-3 py-1 rounded-lg font-black text-slate-400 italic shadow-sm">{patient.time}</span>
                    <span className={`text-[10px] px-3 py-1 rounded-lg font-black uppercase tracking-widest border ${patient.paymentStatus === 'SOLDE' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-amber-50 text-amber-600 border-amber-100'}`}>
                      {patient.paymentStatus}
                    </span>
                  </div>
                </div>
              )) : (
                <div className="p-20 text-center text-slate-300">
                  <Activity size={48} className="mx-auto mb-4 opacity-10" />
                  <p className="font-black text-[10px] uppercase tracking-widest">Aucun patient</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Clinical Area Section: Main examination workspace */}
        <div className="lg:col-span-8 space-y-8">
          {selectedPatient ? (
            <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm p-10">
                <div className="flex justify-between items-start mb-10 border-b border-slate-50 pb-8">
                  <div className="flex gap-6 items-center">
                    <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-[30px] flex items-center justify-center shadow-inner">
                      <UserIcon size={40} />
                    </div>
                    <div>
                      <h2 className="text-3xl font-black italic tracking-tight">{selectedPatient.lastName} {selectedPatient.firstName}</h2>
                      <p className="text-slate-500 font-bold text-sm tracking-tight">DME: {selectedPatient.id} • {selectedPatient.gender === 'M' ? 'Homme' : 'Femme'}</p>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 text-center">
