                    >
                      <Brain size={24} className="text-blue-400" />
                      {loadingAI ? 'ANALYSE EXPERTE EN COURS...' : 'AIDE AU DIAGNOSTIC GEMINI'}
                    </button>
                    <button className="flex-1 border-2 border-slate-100 rounded-[30px] font-black text-xs uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all flex items-center justify-center gap-2">
                      <FlaskConical size={18} /> Labo
                    </button>
                    <button className="flex-1 border-2 border-slate-100 rounded-[30px] font-black text-xs uppercase tracking-widest text-slate-500 hover:bg-slate-50 transition-all flex items-center justify-center gap-2">
                      <Pill size={18} /> Ordo
                    </button>
                  </div>
                </div>
              </div>

              {/* AI Insight Section: Displaying the reasoning from Gemini */}
              {geminiSupport && (
                <div className="bg-blue-600 text-white rounded-[50px] p-12 shadow-2xl shadow-blue-600/30 animate-in zoom-in-95 duration-500 relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-12 opacity-5 group-hover:scale-110 transition-transform duration-700"><Brain size={180} /></div>

                  <h3 className="text-2xl font-black mb-10 flex items-center gap-4 italic relative z-10">
                    <Brain size={32} className="text-blue-200" /> Analyse Clinique Prédictive
                  </h3>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10">
                    <div className="p-8 bg-white/5 rounded-[35px] border border-white/10 backdrop-blur-sm">
                      <h4 className="text-[10px] font-black uppercase text-blue-200 tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-white/10 pb-2">
                        <Activity size={14} /> Hypothèses Diagnostiques
                      </h4>
                      <ul className="space-y-4">
                        {geminiSupport.hypotheses?.map((h: string, i: number) => (
                          <li key={i} className="flex gap-3 text-sm font-black italic">
                            <span className="text-blue-400">#</span> {h}
                          </li>
                        ))}
                      </ul>
                    </div>

                    <div className="p-8 bg-white/5 rounded-[35px] border border-white/10 backdrop-blur-sm">
                      <h4 className="text-[10px] font-black uppercase text-blue-200 tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-white/10 pb-2">
                        <FlaskConical size={14} /> Examens Labo Recommandés
                      </h4>
                      <ul className="space-y-4">
                        {geminiSupport.suggestedLabTests?.map((t: string, i: number) => (
                          <li key={i} className="flex gap-3 text-sm font-bold">
                            <CheckCircle2 size={18} className="text-emerald-400 flex-shrink-0" /> {t}
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>

                  {geminiSupport.clinicalWarnings?.length > 0 && (
                    <div className="mt-10 p-8 bg-rose-500/20 rounded-[35px] border-2 border-rose-400/30 flex gap-6 items-start relative z-10">
                      <div className="w-14 h-14 bg-rose-500 rounded-2xl flex items-center justify-center shadow-lg flex-shrink-0">
                        <AlertTriangle className="text-white" size={28} />
                      </div>
                      <div>
                        <p className="text-[10px] font-black uppercase text-rose-300 tracking-widest mb-2">Alerte Vigilance Clinique (Points de Gravité)</p>
                        <ul className="text-sm font-black italic space-y-2">
                          {geminiSupport.clinicalWarnings.map((w: string, i: number) => <li key={i}>• {w}</li>)}
                        </ul>
                      </div>
                    </div>
                  )}
                </div>
              )}

              <div className="pt-6">
                <button 
                  onClick={completeConsultation}
                  className="w-full bg-emerald-600 text-white py-8 rounded-[40px] font-black shadow-2xl shadow-emerald-600/20 hover:bg-emerald-700 transition-all flex items-center justify-center gap-4 text-xl scale-105 active:scale-100"
                >
                  <Send size={32} /> VALIDER & CLÔTURER LE DOSSIER
                </button>
              </div>
            </div>
          ) : (
            <div className="h-[700px] flex flex-col items-center justify-center bg-white rounded-[50px] border-4 border-dashed border-slate-100 text-slate-300">
              <Stethoscope size={100} className="mb-8 opacity-5 rotate-12" />
              <p className="font-black text-xs uppercase tracking-[0.3em] italic">Sélectionnez un patient pour démarrer la consultation</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Consultation;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Save, Clipboard, Beaker, Pill, AlertTriangle, Sparkles, 
  Send, Heart, Activity, Thermometer, Box, BedDouble, 
  CheckCircle2, Clock, History, FileText, ChevronRight, 
  AlertCircle, ShieldAlert, Plus, X, Search, Info, Users,
  UserCheck, ArrowLeft, Zap, Wallet, Mic, MicOff
} from 'lucide-react';
import { getClinicalSupport } from '../services/geminiService';
import { Role, VisitMotif, Patient, PatientStatus } from '../types';

interface ConsultationProps {
  waitingQueue?: any[];
  setWaitingQueue?: React.Dispatch<React.SetStateAction<any[]>>;
}

const Consultation: React.FC<ConsultationProps> = ({ waitingQueue = [], setWaitingQueue }) => {
  // --- ÉTATS DE NAVIGATION DU MODULE ---
  const [viewMode, setViewMode] = useState<'queue' | 'active'>('queue');
  const [activeStep, setActiveStep] = useState<'anamnese' | 'examen' | 'decision'>('anamnese');

  // --- ÉTATS DU PATIENT ACTIF ---
  const [selectedPatient, setSelectedPatient] = useState<any>(null);

  // Sections Médicales
  const [complaint, setComplaint] = useState("");
  const [history, setHistory] = useState("");
  const [antecedents, setAntecedents] = useState<Record<string, string>>({
    Médicaux: "", Chirurgicaux: "", Allergiques: "", Toxicologiques: ""
  });
  const [systems, setSystems] = useState<Record<string, boolean>>({
    general: false, cardio: false, respiratory: false, digestive: false, neuro: false, urinary: false
  });
  const [physExam, setPhysExam] = useState<Record<string, string>>({
    general: "Patient conscient, orienté",
    cardio: "Bruits du coeur réguliers, pas de souffle",
    resp: "Murmure vésiculaire normal",
    digestive: "Abdomen souple, indolore",
    neuro: "Pas de signe de focalisation"
  });

  // Décisions
  const [prescribedLabs, setPrescribedLabs] = useState<{name: string, urgent: boolean}[]>([]);
  const [prescribedMeds, setPrescribedMeds] = useState<{name: string, dose: string, duration: string}[]>([]);
  const [hospitalization, setHospitalization] = useState<{bed: string, protocol: string} | null>(null);
  const [hospitProtocol, setHospitProtocol] = useState("");

  // IA & Logs
  const [aiSuggestions, setAiSuggestions] = useState<any>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [impactLogs, setImpactLogs] = useState<string[]>([]);

  // --- LOGIQUE DICTÉE VOCALE OPTIMISÉE ---
  const [isListening, setIsListening] = useState<string | null>(null);
  const recognitionRef = useRef<any>(null);
  const currentFieldRef = useRef<string | null>(null);
  const baseTextRef = useRef<string>("");

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'fr-FR';

      recognition.onresult = (event: any) => {
        let sessionTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          sessionTranscript += event.results[i][0].transcript;
        }

        const fieldId = currentFieldRef.current;
        if (fieldId) {
          const updatedText = baseTextRef.current + sessionTranscript;
          updateFieldText(fieldId, updatedText);
        }
      };

      recognition.onend = () => {
        setIsListening(null);
        currentFieldRef.current = null;
      };

      recognition.onerror = (event: any) => {
        if (event.error !== 'no-speech') {
          console.error("Speech recognition error", event.error);
          setIsListening(null);
          currentFieldRef.current = null;
        }
      };

      recognitionRef.current = recognition;
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  const updateFieldText = (fieldId: string, text: string) => {
    if (fieldId === 'complaint') setComplaint(text);
    else if (fieldId === 'history') setHistory(text);
    else if (fieldId === 'hospitProtocol') setHospitProtocol(text);
    else if (fieldId.startsWith('ant-')) {
      const key = fieldId.replace('ant-', '');
      setAntecedents(prev => ({ ...prev, [key]: text }));
    } else if (fieldId.startsWith('phys-')) {
      const key = fieldId.replace('phys-', '');
      setPhysExam(prev => ({ ...prev, [key]: text }));
    }
  };

  const toggleListening = (fieldId: string) => {
    if (!recognitionRef.current) {
      alert("La reconnaissance vocale n'est pas supportée par votre navigateur.");
      return;
    }

    if (isListening === fieldId) {
      recognitionRef.current.stop();
    } else {
      // Si une écoute est déjà en cours, on l'arrête proprement
      if (isListening) {
        recognitionRef.current.stop();
      }

      // Initialisation du texte de base pour ne pas écraser l'existant
      let currentVal = "";
      if (fieldId === 'complaint') currentVal = complaint;
      else if (fieldId === 'history') currentVal = history;
      else if (fieldId === 'hospitProtocol') currentVal = hospitProtocol;
      else if (fieldId.startsWith('ant-')) currentVal = antecedents[fieldId.replace('ant-', '')] || "";
      else if (fieldId.startsWith('phys-')) currentVal = physExam[fieldId.replace('phys-', '')] || "";

      baseTextRef.current = currentVal ? (currentVal.endsWith(' ') ? currentVal : currentVal + " ") : "";
      currentFieldRef.current = fieldId;
      setIsListening(fieldId);

      try {
        recognitionRef.current.start();
      } catch (e) {
        console.warn("Recognition already started or error:", e);
      }
    }
  };

  // Composant Bouton Micro
  const VoiceButton = ({ fieldId }: { fieldId: string }) => (
    <button 
      onClick={(e) => {
        e.preventDefault();
        toggleListening(fieldId);
      }}
      className={`p-2 rounded-xl transition-all shadow-sm flex items-center gap-2 group ${
        isListening === fieldId 
        ? 'bg-rose-500 text-white animate-pulse shadow-rose-500/40' 
        : 'bg-white border border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:shadow-md'
      }`}
      title="Dictée vocale"
    >
      {isListening === fieldId ? <MicOff size={16} /> : <Mic size={16} />}
      {isListening === fieldId && <span className="text-[8px] font-black uppercase tracking-widest md:inline hidden">Stop Dictée</span>}
    </button>
  );

  // --- LOGIQUE DE NAVIGATION ---
  const startConsultation = (patient: any) => {
    setSelectedPatient(patient);
    setComplaint(`Motif: ${patient.motif} - Arrivé à ${patient.time}\n`);
    setViewMode('active');
    setActiveStep('anamnese');
    setImpactLogs([`[DME] Ouverture du dossier de ${patient.lastName}`]);
  };

  const closeConsultation = () => {
    if (setWaitingQueue && selectedPatient) {
      setWaitingQueue(prev => prev.filter(p => p.id !== selectedPatient.id));
    }
    setSelectedPatient(null);
    setViewMode('queue');
    alert("Consultation clôturée. Dossier archivé dans le DME et transmis à la facturation finale.");
  };

  // --- LOGIQUE IA ---
  const handleAiAssist = async () => {
    if (!selectedPatient) return;
    setLoadingAi(true);
    const vitalsStr = `T°: ${selectedPatient.vitals.temp}, TA: ${selectedPatient.vitals.bp}, Pouls: ${selectedPatient.vitals.pulse}`;
    const result = await getClinicalSupport(complaint + " " + history, vitalsStr);
    setAiSuggestions(result);
    setLoadingAi(false);
  };

  // --- ACTIONS AUTOMATIQUES ---
  const addLabTest = (name: string, urgent: boolean = false) => {
    setPrescribedLabs([...prescribedLabs, { name, urgent }]);
    setImpactLogs(prev => [...prev, `[COMPTA] Facture Labo générée: ${urgent ? '8,000' : '5,000'} CFA`, `[LABO] Notification envoyée (Priorité: ${urgent ? 'Haute' : 'Normale'})`]);
  };

  const addMed = (name: string) => {
    setPrescribedMeds([...prescribedMeds, { name, dose: "1cp x 3/j", duration: "5 jours" }]);
    setImpactLogs(prev => [...prev, `[STOCK] Réservation de ${name} en pharmacie`, `[COMPTA] Ajout à la facture patient`]);
  };

  const decideHospit = (bed: string) => {
    setHospitalization({ bed, protocol: hospitProtocol });
    setImpactLogs(prev => [...prev, `[HOSPIT] Lit ${bed} marqué OCCUPÉ`, `[SOINS] Protocole infirmier généré`]);
  };

  return (
    <div className="p-8 max-w-[1600px] mx-auto text-slate-900">

      {/* MODE : SALLE D'ATTENTE */}
      {viewMode === 'queue' && (
        <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="flex justify-between items-end mb-10">
              <div>
                <h1 className="text-4xl font-black tracking-tight">Salle d'Attente Médicale</h1>
                <p className="text-slate-500 font-medium italic">Patients admis à l'accueil en attente de consultation.</p>
              </div>
              <div className="bg-blue-600 text-white px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20">
                {waitingQueue.length} Patients en attente
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {waitingQueue.map((p) => (
                <div key={p.id} className="bg-white rounded-[40px] border border-slate-200 p-8 hover:border-blue-500 hover:shadow-2xl transition-all group relative overflow-hidden">
                   <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform"><Clock size={100} /></div>

                   <div className="flex justify-between items-start mb-6">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-blue-600 transition-colors"><Users size={20} /></div>
                        <span className="text-[10px] font-black text-slate-400 font-mono tracking-widest uppercase">{p.id}</span>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${p.motif === 'URGENCE' ? 'bg-rose-100 text-rose-600' : 'bg-blue-100 text-blue-600'}`}>
                         {p.motif}
                      </span>
                   </div>

                   <h3 className="text-2xl font-black mb-1">{p.lastName} {p.firstName}</h3>
                   <p className="text-sm text-slate-500 font-medium mb-6">{p.age} ans • {p.gender === 'M' ? 'Masculin' : 'Féminin'}</p>

                   <div className="grid grid-cols-3 gap-3 mb-8">
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">T°</p>
                         <p className="text-sm font-black text-rose-600">{p.vitals.temp}°C</p>
                      </div>
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">TA</p>
                         <p className="text-sm font-black text-slate-900">{p.vitals.bp}</p>
                      </div>
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">SPO2</p>
                         <p className="text-sm font-black text-emerald-600">{p.vitals.spo2}%</p>
                      </div>
                   </div>

                   <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                      <div className="flex items-center gap-2">
                         <div className={`w-2 h-2 rounded-full ${p.paymentStatus === 'SOLDE' ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></div>
                         <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">{p.paymentStatus}</span>
                      </div>
                      <button 
                        onClick={() => startConsultation(p)}
                        className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 transition-all flex items-center gap-2"
                      >
                        Appeler <ChevronRight size={14} />
                      </button>
                   </div>
                </div>
              ))}

              {waitingQueue.length === 0 && (
                <div className="col-span-full py-32 text-center bg-slate-100 rounded-[50px] border-4 border-dashed border-slate-200">
                   <Users size={64} className="mx-auto text-slate-300 mb-6 opacity-20" />
                   <h3 className="text-xl font-black text-slate-400 uppercase tracking-widest">Aucun patient en attente</h3>
                   <p className="text-slate-500 mt-2 font-medium italic">Reposez-vous docteur, la file est vide.</p>
                </div>
              )}
           </div>
        </div>
      )}

      {/* MODE : CONSULTATION ACTIVE */}
      {viewMode === 'active' && selectedPatient && (
        <div className="animate-in fade-in zoom-in-95 duration-500">
          {/* HEADER PATIENT FIXE */}
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm sticky top-4 z-30">
            <div className="flex items-center gap-6">
              <button 
                onClick={() => setViewMode('queue')}
                className="p-3 hover:bg-slate-100 rounded-2xl transition-colors text-slate-400"
              >
                <ArrowLeft size={20} />
              </button>
              <div className="w-16 h-16 bg-blue-600 rounded-2xl overflow-hidden border-4 border-white shadow-xl rotate-3">
                <img src={`https://picsum.photos/64/64?u=${selectedPatient.lastName}`} alt="Patient" />
              </div>
              <div>
                <div className="flex items-center gap-3">
                  <h1 className="text-2xl font-black tracking-tight">{selectedPatient.lastName} {selectedPatient.firstName}</h1>
                  <span className="bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest italic">Consultation en cours</span>
                </div>
                <p className="text-sm font-medium text-slate-500 flex items-center gap-2 mt-1">
                  <span className="font-mono font-bold text-blue-600">{selectedPatient.id}</span>
                  • {selectedPatient.age} ans • {selectedPatient.gender === 'M' ? 'H' : 'F'} • Arrivée: {selectedPatient.time}
                </p>
              </div>
            </div>
            <div className="flex gap-3">
              <button className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-600 font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-slate-200 transition-all">
                <History size={16} /> Historique DME
              </button>
              <button 
                onClick={closeConsultation}
                className="flex items-center gap-2 bg-blue-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-600/20 hover:bg-blue-700 active:scale-95 transition-all"
              >
                <Save size={16} /> Clôturer & Archiver
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* COLONNE GAUCHE : RAISONNEMENT STRUCTURE */}
            <div className="lg:col-span-8 space-y-8">

              <div className="flex bg-white p-2 rounded-[24px] border border-slate-200 shadow-sm gap-2">
                {[
                  { id: 'anamnese', label: '1. Anamnèse', icon: Clipboard },
                  { id: 'examen', label: '2. Examen Physique', icon: Activity },
                  { id: 'decision', label: '3. Prescription & Décision', icon: Box },
                ].map(step => (
                  <button 
                    key={step.id} 
                    onClick={() => setActiveStep(step.id as any)}
                    className={`flex-1 flex items-center justify-center gap-3 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeStep === step.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    <step.icon size={16} /> {step.label}
                  </button>
                ))}
              </div>

              <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden min-h-[600px]">

                {activeStep === 'anamnese' && (
                  <div className="p-10 space-y-10 animate-in fade-in slide-in-from-right-4 duration-500">
                    <section>
                      <div className="flex justify-between items-center mb-6 border-b border-blue-50 pb-2">
                        <h3 className="text-xs font-black text-blue-600 uppercase tracking-[0.2em] flex items-center gap-2">
                          <Info size={16} /> Histoire de la maladie actuelle
                        </h3>
                        <VoiceButton fieldId="complaint" />
                      </div>
                      <textarea 
                        value={complaint}
                        onChange={(e) => setComplaint(e.target.value)}
                        placeholder="Détaillez ici les symptômes, la durée et l'intensité..."
                        className={`w-full p-6 bg-slate-50 border-2 rounded-3xl outline-none transition-all font-bold text-lg italic min-h-[150px] ${isListening === 'complaint' ? 'border-rose-500 bg-rose-50/10 shadow-inner' : 'border-slate-100 focus:border-blue-500'}`}
                      />
                    </section>

                    <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <div>
                        <h3 className="text-xs font-black text-rose-600 uppercase tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-rose-50 pb-2">
                          <ShieldAlert size={16} /> Antécédents Personnels
                        </h3>
                        <div className="space-y-4">
                          {Object.keys(antecedents).map(ant => (
                            <div key={ant}>
                              <div className="flex justify-between items-center mb-1">
                                <label className="block text-[9px] font-black text-slate-400 uppercase ml-2">{ant}</label>
                                <VoiceButton fieldId={`ant-${ant}`} />
                              </div>
                              <input 
                                type="text" 
                                className={`w-full p-3 bg-slate-50 border rounded-xl outline-none transition-all text-sm font-medium ${isListening === `ant-${ant}` ? 'border-rose-500 bg-rose-50/10 shadow-inner font-bold' : 'border-slate-100 focus:border-rose-300'}`} 
                                value={antecedents[ant]}
                                onChange={e => setAntecedents(prev => ({ ...prev, [ant]: e.target.value }))}
