                                <textarea 
                                  placeholder="Instructions spécifiques pour les infirmiers (ex: Surveiller TA toutes les 2h)..." 
                                  value={hospitProtocol}
                                  onChange={e => setHospitProtocol(e.target.value)}
                                  className={`w-full mt-4 p-4 border rounded-2xl outline-none transition-all text-xs font-bold min-h-[80px] ${isListening === 'hospitProtocol' ? 'border-rose-500 bg-white font-bold' : 'border-rose-200 bg-white/50 focus:bg-white'}`} 
                                />
                             </div>
                             <div className="w-24 h-24 rounded-[32px] bg-white flex flex-col items-center justify-center text-rose-500 border-2 border-rose-100 shadow-inner">
                                <AlertCircle size={32} />
                             </div>
