                             <p className="text-[10px] font-black text-slate-500 uppercase italic mb-4">Ordonnance Digitale</p>
                             <div className="space-y-4 h-40 overflow-y-auto pr-2 custom-scrollbar">
                                {prescribedMeds.map((m, i) => (
                                  <div key={i} className="border-b border-white/5 pb-2">
                                     <p className="text-xs font-black text-emerald-400 italic">{m.name}</p>
                                     <p className="text-[9px] opacity-50 font-bold">{m.dose} • {m.duration}</p>
                                  </div>
