  const [physExam, setPhysExam] = useState<Record<string, string>>({
    general: "Patient conscient, orienté",
    cardio: "Bruits du coeur réguliers, pas de souffle",
    resp: "Murmure vésiculaire normal",
    digestive: "Abdomen souple, indolore",
    neuro: "Pas de signe de focalisation"
  });

  // Décisions
  const [prescribedLabs, setPrescribedLabs] = useState<{name: string, urgent: boolean}[]>([]);
  const [prescribedMeds, setPrescribedMeds] = useState<{name: string, dose: string, duration: string}[]>([]);
  const [hospitalization, setHospitalization] = useState<{bed: string, protocol: string} | null>(null);
  const [hospitProtocol, setHospitProtocol] = useState("");

  // IA & Logs
  const [aiSuggestions, setAiSuggestions] = useState<any>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [impactLogs, setImpactLogs] = useState<string[]>([]);

  // --- LOGIQUE ENREGISTREMENT AUDIO (MediaRecorder + Gemini) ---
  const [isRecording, setIsRecording] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState<string | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const startRecording = async (fieldId: string) => {
    try {
      // Vérification basique du support navigateur
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("BrowserNotSupported");
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Détection du type MIME supporté par le navigateur pour l'enregistrement
      let mimeType = '';
      if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
        mimeType = 'audio/webm;codecs=opus';
      } else if (MediaRecorder.isTypeSupported('audio/webm')) {
        mimeType = 'audio/webm';
      } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
        mimeType = 'audio/mp4';
      } else if (MediaRecorder.isTypeSupported('audio/ogg')) {
        mimeType = 'audio/ogg';
      }

      // Si aucun type spécifique n'est trouvé, on laisse le navigateur choisir par défaut
      const options = mimeType ? { mimeType } : undefined;
      const mediaRecorder = new MediaRecorder(stream, options);

      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        // Utiliser le mimeType réel configuré par le MediaRecorder s'il est disponible
        const finalMimeType = mediaRecorder.mimeType || mimeType || 'audio/webm';
        const audioBlob = new Blob(audioChunksRef.current, { type: finalMimeType });

        const tracks = stream.getTracks();
        tracks.forEach(track => track.stop()); // Libérer le micro immédiatement

        setIsRecording(null);
        setIsTranscribing(fieldId);

        try {
          const base64Audio = await blobToBase64(audioBlob);
          const transcription = await transcribeMedicalAudio(base64Audio, finalMimeType);

          if (transcription) {
            updateFieldText(fieldId, transcription, true); // true = append
          }
        } catch (error) {
          console.error("Erreur traitement audio:", error);
          alert("Erreur lors de la transcription par l'IA.");
        } finally {
          setIsTranscribing(null);
        }
      };

      mediaRecorder.start();
      setIsRecording(fieldId);

    } catch (err: any) {
      console.error("Erreur accès micro:", err);
      let message = "Impossible d'accéder au microphone.";

      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        message = "Accès au microphone refusé. Veuillez cliquer sur l'icône de cadenas dans la barre d'adresse pour autoriser le microphone.";
      } else if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
        message = "Aucun microphone détecté. Veuillez vérifier vos branchements.";
      } else if (err.name === 'NotReadableError' || err.name === 'TrackStartError') {
        message = "Le microphone est inaccessible. Il est peut-être utilisé par une autre application.";
      } else if (err.message && (err.message.includes('system') || err.message.includes('Permission denied'))) {
        message = "Accès refusé par le système. Vérifiez les paramètres de confidentialité de votre système d'exploitation (Windows/macOS) pour autoriser le navigateur à utiliser le micro.";
      } else if (err.message === 'BrowserNotSupported') {
        message = "Votre navigateur ne supporte pas l'enregistrement audio. Veuillez utiliser Chrome, Firefox ou Edge.";
      }

      alert(message);
      setIsRecording(null);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }
  };

  const toggleRecording = (fieldId: string) => {
    if (isRecording === fieldId) {
      stopRecording();
    } else {
      if (isRecording) stopRecording(); // Arrêter un autre enregistrement en cours
      startRecording(fieldId);
    }
  };

  const updateFieldText = (fieldId: string, text: string, append: boolean = false) => {
    const processUpdate = (prev: string) => {
      const cleanText = text.trim();
      if (!append) return cleanText;
      return prev ? `${prev} ${cleanText}` : cleanText;
    };

    if (fieldId === 'complaint') setComplaint(prev => processUpdate(prev));
    else if (fieldId === 'history') setHistory(prev => processUpdate(prev));
    else if (fieldId === 'hospitProtocol') setHospitProtocol(prev => processUpdate(prev));
    else if (fieldId.startsWith('ant-')) {
      const key = fieldId.replace('ant-', '');
      setAntecedents(prev => ({ ...prev, [key]: processUpdate(prev[key]) }));
    } else if (fieldId.startsWith('phys-')) {
      const key = fieldId.replace('phys-', '');
      setPhysExam(prev => ({ ...prev, [key]: processUpdate(prev[key]) }));
    }
  };

  const VoiceButton = ({ fieldId }: { fieldId: string }) => {
    const active = isRecording === fieldId;
    const processing = isTranscribing === fieldId;

    return (
      <button 
        onClick={(e) => {
          e.preventDefault();
          e.stopPropagation();
          if (!processing) toggleRecording(fieldId);
        }}
        disabled={processing}
        className={`p-2 rounded-xl transition-all shadow-sm flex items-center gap-2 group border ${
          active
          ? 'bg-rose-500 border-rose-600 text-white animate-pulse shadow-rose-500/40' 
          : processing 
            ? 'bg-amber-100 border-amber-200 text-amber-600 cursor-wait'
            : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-300'
        }`}
        title={active ? "Arrêter" : processing ? "Analyse..." : "Dicter"}
      >
        {processing ? <Loader2 size={16} className="animate-spin" /> : active ? <MicOff size={16} /> : <Mic size={16} />}
        {(active || processing) && (
          <span className="text-[9px] font-black uppercase tracking-widest md:inline hidden">
            {active ? "Stop" : "IA..."}
          </span>
        )}
      </button>
    );
  };

  // --- LOGIQUE DE NAVIGATION ---
  const startConsultation = (patient: any) => {
    setSelectedPatient(patient);
    setComplaint(`Motif: ${patient.motif} - Arrivé à ${patient.time}\n`);
    setViewMode('active');
    setActiveStep('anamnese');
    setImpactLogs([`[DME] Ouverture du dossier de ${patient.lastName}`]);
  };

  const closeConsultation = () => {
    if (setWaitingQueue && selectedPatient) {
      setWaitingQueue(prev => prev.filter(p => p.id !== selectedPatient.id));
    }
    setSelectedPatient(null);
    setViewMode('queue');
    alert("Consultation clôturée. Dossier archivé dans le DME et transmis à la facturation finale.");
  };

  // --- LOGIQUE IA ---
  const handleAiAssist = async () => {
    if (!selectedPatient) return;
    setLoadingAi(true);
    const vitalsStr = `T°: ${selectedPatient.vitals.temp}, TA: ${selectedPatient.vitals.bp}, Pouls: ${selectedPatient.vitals.pulse}`;
    const result = await getClinicalSupport(complaint + " " + history, vitalsStr);
    setAiSuggestions(result);
    setLoadingAi(false);
  };

  // --- ACTIONS AUTOMATIQUES ---
  const addLabTest = (name: string, urgent: boolean = false) => {
    setPrescribedLabs([...prescribedLabs, { name, urgent }]);
    setImpactLogs(prev => [...prev, `[COMPTA] Facture Labo générée: ${urgent ? '8,000' : '5,000'} CFA`, `[LABO] Notification envoyée (Priorité: ${urgent ? 'Haute' : 'Normale'})`]);
  };

  const addMed = (name: string) => {
    setPrescribedMeds([...prescribedMeds, { name, dose: "1cp x 3/j", duration: "5 jours" }]);
    setImpactLogs(prev => [...prev, `[STOCK] Réservation de ${name} en pharmacie`, `[COMPTA] Ajout à la facture patient`]);
  };

  const decideHospit = (bed: string) => {
    setHospitalization({ bed, protocol: hospitProtocol });
    setImpactLogs(prev => [...prev, `[HOSPIT] Lit ${bed} marqué OCCUPÉ`, `[SOINS] Protocole infirmier généré`]);
  };

  return (
    <div className="p-8 max-w-[1600px] mx-auto text-slate-900">

      {/* MODE : SALLE D'ATTENTE */}
      {viewMode === 'queue' && (
        <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
           <div className="flex justify-between items-end mb-10">
              <div>
                <h1 className="text-4xl font-black tracking-tight">Salle d'Attente Médicale</h1>
                <p className="text-slate-500 font-medium italic">Patients admis à l'accueil en attente de consultation.</p>
              </div>
              <div className="bg-blue-600 text-white px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20">
                {waitingQueue.length} Patients en attente
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {waitingQueue.map((p) => (
                <div key={p.id} className="bg-white rounded-[40px] border border-slate-200 p-8 hover:border-blue-500 hover:shadow-2xl transition-all group relative overflow-hidden">
                   <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform"><Clock size={100} /></div>

                   <div className="flex justify-between items-start mb-6">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-blue-600 transition-colors"><Users size={20} /></div>
                        <span className="text-[10px] font-black text-slate-400 font-mono tracking-widest uppercase">{p.id}</span>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${p.motif === 'URGENCE' ? 'bg-rose-100 text-rose-600' : 'bg-blue-100 text-blue-600'}`}>
                         {p.motif}
                      </span>
                   </div>

                   <h3 className="text-2xl font-black mb-1">{p.lastName} {p.firstName}</h3>
                   <p className="text-sm text-slate-500 font-medium mb-6">{p.age} ans • {p.gender === 'M' ? 'Masculin' : 'Féminin'}</p>

                   <div className="grid grid-cols-3 gap-3 mb-8">
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">T°</p>
                         <p className="text-sm font-black text-rose-600">{p.vitals.temp}°C</p>
                      </div>
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">TA</p>
                         <p className="text-sm font-black text-slate-900">{p.vitals.bp}</p>
                      </div>
                      <div className="bg-slate-50 p-3 rounded-2xl text-center border border-slate-100">
                         <p className="text-[8px] font-black text-slate-400 uppercase mb-1">SPO2</p>
                         <p className="text-sm font-black text-emerald-600">{p.vitals.spo2}%</p>
                      </div>
                   </div>

                   <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                      <div className="flex items-center gap-2">
                         <div className={`w-2 h-2 rounded-full ${p.paymentStatus === 'SOLDE' ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></div>
                         <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">{p.paymentStatus}</span>
                      </div>
                      <button 
                        onClick={() => startConsultation(p)}
                        className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 transition-all flex items-center gap-2"
                      >
                        Appeler <ChevronRight size={14} />
                      </button>
                   </div>
                </div>
              ))}

              {waitingQueue.length === 0 && (
                <div className="col-span-full py-32 text-center bg-slate-100 rounded-[50px] border-4 border-dashed border-slate-200">
                   <Users size={64} className="mx-auto text-slate-300 mb-6 opacity-20" />
                   <h3 className="text-xl font-black text-slate-400 uppercase tracking-widest">Aucun patient en attente</h3>
                   <p className="text-slate-500 mt-2 font-medium italic">Reposez-vous docteur, la file est vide.</p>
                </div>
              )}
           </div>
        </div>
      )}

      {/* MODE : CONSULTATION ACTIVE */}
      {viewMode === 'active' && selectedPatient && (
        <div className="animate-in fade-in zoom-in-95 duration-500">
          {/* HEADER PATIENT FIXE */}
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm sticky top-4 z-30">
            <div className="flex items-center gap-6">
              <button 
                onClick={() => setViewMode('queue')}
                className="p-3 hover:bg-slate-100 rounded-2xl transition-colors text-slate-400"
              >
                <ArrowLeft size={20} />
              </button>
              <div className="w-16 h-16 bg-blue-600 rounded-2xl overflow-hidden border-4 border-white shadow-xl rotate-3">
                <img src={`https://picsum.photos/64/64?u=${selectedPatient.lastName}`} alt="Patient" />
              </div>
              <div>
                <div className="flex items-center gap-3">
                  <h1 className="text-2xl font-black tracking-tight">{selectedPatient.lastName} {selectedPatient.firstName}</h1>
                  <span className="bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest italic">Consultation en cours</span>
                </div>
                <p className="text-sm font-medium text-slate-500 flex items-center gap-2 mt-1">
                  <span className="font-mono font-bold text-blue-600">{selectedPatient.id}</span>
                  • {selectedPatient.age} ans • {selectedPatient.gender === 'M' ? 'H' : 'F'} • Arrivée: {selectedPatient.time}
                </p>
              </div>
            </div>
            <div className="flex gap-3">
              <button className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-600 font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-slate-200 transition-all">
                <History size={16} /> Historique DME
              </button>
              <button 
                onClick={closeConsultation}
                className="flex items-center gap-2 bg-blue-600 text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-600/20 hover:bg-blue-700 active:scale-95 transition-all"
              >
                <Save size={16} /> Clôturer & Archiver
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

            {/* COLONNE GAUCHE : RAISONNEMENT STRUCTURE */}
            <div className="lg:col-span-8 space-y-8">

              <div className="flex bg-white p-2 rounded-[24px] border border-slate-200 shadow-sm gap-2">
                {[
                  { id: 'anamnese', label: '1. Anamnèse', icon: Clipboard },
                  { id: 'examen', label: '2. Examen Physique', icon: Activity },
                  { id: 'decision', label: '3. Prescription & Décision', icon: Box },
                ].map(step => (
                  <button 
                    key={step.id} 
                    onClick={() => setActiveStep(step.id as any)}
                    className={`flex-1 flex items-center justify-center gap-3 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeStep === step.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    <step.icon size={16} /> {step.label}
                  </button>
                ))}
              </div>

              <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden min-h-[600px]">

                {activeStep === 'anamnese' && (
                  <div className="p-10 space-y-10 animate-in fade-in slide-in-from-right-4 duration-500">
                    <section>
                      <div className="flex justify-between items-center mb-6 border-b border-blue-50 pb-2">
                        <h3 className="text-xs font-black text-blue-600 uppercase tracking-[0.2em] flex items-center gap-2">
                          <Info size={16} /> Histoire de la maladie actuelle
                        </h3>
                        <VoiceButton fieldId="complaint" />
                      </div>
                      <textarea 
                        value={complaint}
                        onChange={(e) => setComplaint(e.target.value)}
                        placeholder="Détaillez ici les symptômes, la durée et l'intensité..."
                        className={`w-full p-6 bg-slate-50 border-2 rounded-3xl outline-none transition-all font-bold text-lg italic min-h-[150px] ${isRecording === 'complaint' ? 'border-rose-500 bg-rose-50/10' : 'border-slate-100 focus:border-blue-500'}`}
                      />
                    </section>

                    <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <div>
                        <h3 className="text-xs font-black text-rose-600 uppercase tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-rose-50 pb-2">
                          <ShieldAlert size={16} /> Antécédents Personnels
                        </h3>
                        <div className="space-y-4">
                          {Object.keys(antecedents).map(ant => (
                            <div key={ant}>
                              <div className="flex justify-between items-center mb-1">
                                <label className="block text-[9px] font-black text-slate-400 uppercase ml-2">{ant}</label>
                                <VoiceButton fieldId={`ant-${ant}`} />
                              </div>
                              <input 
                                type="text" 
                                className={`w-full p-3 bg-slate-50 border rounded-xl outline-none transition-all text-sm font-medium ${isRecording === `ant-${ant}` ? 'border-rose-500 bg-rose-50/10' : 'border-slate-100 focus:border-rose-300'}`} 
                                value={antecedents[ant]}
                                onChange={e => setAntecedents(prev => ({ ...prev, [ant]: e.target.value }))}
                                placeholder="Néant..." 
                              />
                            </div>
                          ))}
                        </div>
                      </div>
                      <div>
                        <h3 className="text-xs font-black text-emerald-600 uppercase tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-emerald-50 pb-2">
                          <Users size={16} /> Histoire Familiale & Sociale
                        </h3>
                        <div className="space-y-4">
                          <div>
                            <div className="flex justify-between items-center mb-1">
                              <label className="block text-[9px] font-black text-slate-400 uppercase ml-2">Commentaires Famille</label>
                              <VoiceButton fieldId="history" />
                            </div>
                            <textarea 
                              className={`w-full p-3 bg-slate-50 border rounded-xl h-24 outline-none transition-all text-sm ${isRecording === 'history' ? 'border-rose-500 bg-rose-50/10' : 'border-slate-100 focus:border-emerald-300'}`} 
                              value={history}
                              onChange={e => setHistory(e.target.value)}
                              placeholder="Diabète, HTA, cardiopathies..." 
                            />
                          </div>
                        </div>
                      </div>
                    </section>

                    <section>
                      <h3 className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-indigo-50 pb-2">
                        <Activity size={16} /> Revue des Systèmes (Cochez les points d'appel)
                      </h3>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {Object.keys(systems).map(sys => (
                          <button 
                            key={sys}
                            onClick={() => setSystems({...systems, [sys]: !systems[sys]})}
                            className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${systems[sys] ? 'border-indigo-500 bg-indigo-50 shadow-md' : 'border-slate-100 bg-slate-50'}`}
                          >
                            <span className="text-[10px] font-black uppercase tracking-tighter">{sys}</span>
                            {systems[sys] ? <CheckCircle2 size={16} className="text-indigo-600" /> : <Plus size={16} className="text-slate-300" />}
                          </button>
                        ))}
                      </div>
                    </section>
                  </div>
                )}

                {activeStep === 'examen' && (
                  <div className="p-10 space-y-10 animate-in fade-in slide-in-from-right-4 duration-500">
                    <section className="grid grid-cols-3 gap-6 bg-slate-900 p-8 rounded-[32px] text-white">
                       <div className="text-center">
                          <p className="text-[10px] font-black text-slate-500 uppercase mb-2 italic">Température</p>
                          <p className="text-3xl font-black text-rose-400">{selectedPatient.vitals.temp} <span className="text-sm font-normal opacity-50">°C</span></p>
                       </div>
                       <div className="text-center border-x border-white/10">
                          <p className="text-[10px] font-black text-slate-500 uppercase mb-2 italic">Tension Art.</p>
                          <p className="text-3xl font-black">{selectedPatient.vitals.bp} <span className="text-sm font-normal opacity-50">mmHg</span></p>
                       </div>
                       <div className="text-center">
                          <p className="text-[10px] font-black text-slate-500 uppercase mb-2 italic">Fréq. Card.</p>
                          <p className="text-3xl font-black text-blue-400">{selectedPatient.vitals.pulse} <span className="text-sm font-normal opacity-50">bpm</span></p>
                       </div>
                    </section>

                    <div className="space-y-6">
                       {Object.keys(physExam).map(part => (
                         <div key={part} className="group">
                            <div className="flex justify-between items-center mb-2 ml-4">
                               <label className="block text-[10px] font-black text-slate-400 uppercase flex items-center gap-2 uppercase tracking-widest">
                                  <div className="w-1.5 h-1.5 bg-blue-500 rounded-full"></div> Appareil {part}
                               </label>
                               <VoiceButton fieldId={`phys-${part}`} />
                            </div>
                            <input 
                              type="text" 
                              value={physExam[part]}
                              onChange={(e) => setPhysExam({...physExam, [part]: e.target.value})}
                              className={`w-full p-4 bg-slate-50 border rounded-2xl outline-none transition-all font-bold text-slate-700 ${isRecording === `phys-${part}` ? 'border-rose-500 bg-rose-50/10' : 'border-slate-100 focus:bg-white focus:border-blue-500'}`}
                            />
                         </div>
                       ))}
                    </div>
                  </div>
                )}

                {activeStep === 'decision' && (
                  <div className="p-10 space-y-10 animate-in fade-in slide-in-from-right-4 duration-500">

                    {/* LABO */}
                    <section>
                      <h3 className="text-xs font-black text-purple-600 uppercase tracking-[0.2em] mb-6 flex items-center gap-2 border-b border-purple-50 pb-2 flex-1">
                        <Beaker size={16} /> Prescription Laboratoire
                      </h3>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="p-6 bg-slate-50 border border-slate-100 rounded-3xl space-y-4">
                           <p className="text-[10px] font-black text-slate-400 uppercase italic">Catalogue SIH</p>
                           <div className="flex flex-wrap gap-2">
                              {['NFS', 'Goutte Épaisse', 'Glycémie', 'CRP', 'ECBU', 'Widal'].map(test => (
                                <button key={test} onClick={() => addLabTest(test)} className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-[10px] font-black uppercase hover:border-purple-500 hover:text-purple-600 transition-all">+ {test}</button>
                              ))}
                           </div>
