                    <button onClick={() => setAiSuggestions(null)} className="w-full text-[9px] font-black text-slate-600 py-3 border border-white/5 rounded-xl uppercase tracking-widest">Réinitialiser</button>
                  </div>
                )}
              </div>

              {/* HISTORIQUE DME */}
              <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm p-8 space-y-6">
                 <div className="flex items-center gap-3 border-b border-slate-50 pb-4">
                    <div className="p-3 bg-slate-100 text-slate-600 rounded-xl"><History size={20} /></div>
                    <h3 className="font-black italic">Antécédents du Dossier</h3>
                 </div>

                 <div className="space-y-6">
                    {[
                      { date: '12/05/2024', type: 'Consultation', desc: 'Dr. Sarr - Grippe suspectée', color: 'blue' },
                      { date: '15/12/2023', type: 'Hospitalisation', desc: '5 jours - Paludisme grave', color: 'rose' },
